function setupLocationCombobox({ input, menu, toggle, field, options = LANDING_LOCATION_OPTIONS, onEnter }) {
  if (!input || !menu) return;
  const renderOptions = (filter = "") => {
    const needle = filter.trim().toLowerCase();
    const items = options.filter((item) => !needle || item.toLowerCase().includes(needle));
    menu.innerHTML = items.length ? items.map(
      (item) => `<li role="option" tabindex="-1" data-value="${escapeHtml(item)}">${escapeHtml(item)}</li>`
    ).join("") : `<li class="location-combobox-empty" role="presentation">No matches</li>`;
  };
  const setExpanded = (open) => {
    input.setAttribute("aria-expanded", open ? "true" : "false");
    toggle?.setAttribute("aria-expanded", open ? "true" : "false");
    field?.classList.toggle("open", open);
  };
  const openMenu = () => {
    renderOptions(input.value);
    menu.hidden = false;
    setExpanded(true);
  };
  const closeMenu = () => {
    menu.hidden = true;
    setExpanded(false);
  };
  renderOptions();
  toggle?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    if (menu.hidden) {
      openMenu();
      input.focus();
    } else {
      closeMenu();
    }
  });
  input.addEventListener("focus", () => openMenu());
  input.addEventListener("input", () => {
    renderOptions(input.value);
    openMenu();
  });
  menu.addEventListener("click", (event) => {
    const option = event.target.closest("[data-value]");
    if (!option) return;
    input.value = option.dataset.value || "";
    closeMenu();
  });
  input.addEventListener("keydown", (event) => {
    if (event.key === "Escape") {
      event.stopPropagation();
      closeMenu();
      return;
    }
    if (event.key === "Enter" && !event.shiftKey) {
      const matches = [...menu.querySelectorAll("[data-value]")];
      if (!menu.hidden && matches.length === 1) {
        event.preventDefault();
        input.value = matches[0].dataset.value || input.value;
        closeMenu();
        return;
      }
      closeMenu();
      if (onEnter) {
        event.preventDefault();
        onEnter();
      }
    }
  });
  document.addEventListener("click", (event) => {
    if (!field?.contains(event.target)) closeMenu();
  });
}
